// Code Pro — sitemap discovery (All Items)
// Raise Timeout for multi-site batches. Expand carefully (maxUrls / Max Output Items).
const sites = $input.all().map((i) => i.json.website || i.json.Website);

const results = await utils.sitemap.fromWebsites(sites, {
  expand: false,          // set true to walk indexes → page URLs
  websiteConcurrency: 3,
  concurrency: 4,
  timeoutMs: 8000,
  maxUrls: 5000,
});

return results.map((r, index) => ({
  json: {
    website: r.website,
    found: r.found,
    sourceUrl: r.sourceUrl,
    kind: r.kind,
    robotsSitemaps: r.robotsSitemaps,
    // rawXml can be large — keep only when you need it
    hasXml: !!r.rawXml,
    xmlLength: r.rawXml ? r.rawXml.length : 0,
    attemptCount: r.attempts?.length ?? 0,
    // Uncomment for page URL fan-out instead of one item per site:
    // urls: r.urls,
    // truncated: r.truncated,
  },
  pairedItem: { item: index },
}));
